const staticData = $getWorkflowStaticData('global');
const env = {
  granolaApiBaseUrl: $env.GRANOLA_API_BASE_URL || 'https://api.granola.ai/v1',
  exportFolders: ($env.GRANOLA_EXPORT_FOLDERS || 'Exports/Markdown,Exports/1to1,Exports/Meetings').split(',').map(v => v.trim()).filter(Boolean),
  includeTranscript: String($env.INCLUDE_TRANSCRIPT || 'true').toLowerCase() === 'true',
  notesVaultRoot: ($env.NOTES_VAULT_ROOT || '/data/notes').replace(/\/$/, ''),
  bootstrapUpdatedAfter: $env.GRANOLA_BOOTSTRAP_UPDATED_AFTER || '2026-04-01T00:00:00Z',
  subpathMap: (() => { try { return JSON.parse($env.OPTIONAL_SUBPATH_MAP || '{}'); } catch { return {}; } })()
};
const checkpointBefore = staticData.granolaCheckpointUpdatedAt || env.bootstrapUpdatedAfter;
staticData._run = { checkpointBefore, checkpointAfterCandidate: checkpointBefore, scanned: 0, matched: 0, written: 0, skipped: 0, failed: 0, pages: 0 };
return [{ json: { cursor: '', checkpointBefore, accumulated: [], env } }];

const prev = $('Load Checkpoint').first().json;
const page = $json;
const notes = Array.isArray(page.notes) ? page.notes : [];
const accumulated = (prev.accumulated || []).concat(notes);
const staticData = $getWorkflowStaticData('global');
if (staticData._run) staticData._run.pages += 1;
return [{ json: { ...prev, accumulated, hasMore: Boolean(page.hasMore), cursor: page.cursor || '' } }];

function slugify(input) {
  return String(input || '').normalize('NFKD').replace(/[\u0300-\u036f]/g, '').toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-+|-+$/g, '').slice(0, 80);
}
function ymd(iso) {
  const d = new Date(iso);
  return { yyyy: d.getUTCFullYear(), mm: String(d.getUTCMonth() + 1).padStart(2, '0'), dd: String(d.getUTCDate()).padStart(2, '0') };
}
function yamlScalar(v) {
  return String(v).replace(/\n/g, ' ').replace(/"/g, '\\"');
}
const staticData = $getWorkflowStaticData('global');
const env = $('Loop Candidates').first().json.env;
const before = $('Loop Candidates').first().json.checkpointBefore;
const note = $json;
const folders = (note.folder_membership || []).map(f => typeof f === 'string' ? f : (f.name || '')).filter(Boolean);
if (staticData._run) staticData._run.scanned += 1;
if (!folders.some(f => env.exportFolders.includes(f))) {
  if (staticData._run) staticData._run.skipped += 1;
  return [{ json: { skipWrite: true, reason: 'outside_export_folder' } }];
}
const noteId = note.id || $('Loop Candidates').first().json.note_id;
const title = note.title || (note.calendar_event && note.calendar_event.title) || noteId;
const slug = slugify(title) || noteId;
const updatedAt = note.updated_at || $('Loop Candidates').first().json.updated_at || before;
const createdAt = note.created_at || updatedAt;
const d = ymd(createdAt);
const chosenFolder = folders.find(f => env.exportFolders.includes(f));
const mappedSubpath = env.subpathMap[chosenFolder] || 'meetings';
const dir = `${env.notesVaultRoot}/${mappedSubpath}/${d.yyyy}/${d.mm}`.replace(/\\+/g, '/');
const fileName = `${d.yyyy}-${d.mm}-${d.dd}__${slug}__${noteId}.md`;
const filePath = `${dir}/${fileName}`;
const front = ['---', 'source: granola', `granola_note_id: ${yamlScalar(noteId)}`];
if (title) front.push(`title: "${yamlScalar(title)}"`);
if (createdAt) front.push(`created_at: ${createdAt}`);
if (updatedAt) front.push(`updated_at: ${updatedAt}`);
if (note.owner && note.owner.name) front.push(`owner_name: "${yamlScalar(note.owner.name)}"`);
if (note.owner && note.owner.email) front.push(`owner_email: "${yamlScalar(note.owner.email)}"`);
if (folders.length) { front.push('folders:'); folders.forEach(f => front.push(`  - "${yamlScalar(f)}"`)); }
const attendees = Array.isArray(note.attendees) ? note.attendees : [];
if (attendees.length) { front.push('attendees:'); attendees.forEach(a => front.push(`  - "${yamlScalar(typeof a === 'string' ? a : (a.name || ''))}"`)); }
if (note.calendar_event && note.calendar_event.title) front.push(`calendar_event_title: "${yamlScalar(note.calendar_event.title)}"`);
if (note.calendar_event && note.calendar_event.scheduled_start_time) front.push(`scheduled_start_time: ${note.calendar_event.scheduled_start_time}`);
if (note.calendar_event && note.calendar_event.scheduled_end_time) front.push(`scheduled_end_time: ${note.calendar_event.scheduled_end_time}`);
front.push(`exported_at: ${new Date().toISOString()}`);
front.push('---');
const summary = note.summary_markdown || note.summary || '';
const transcript = Array.isArray(note.transcript) ? note.transcript : [];
let markdown = `${front.join('\n')}\n\n# ${title}\n\n## Summary\n\n${summary || '_No summary provided._'}\n`;
if (env.includeTranscript && transcript.length) {
  markdown += '\n## Transcript\n\n';
  transcript.forEach(line => {
    markdown += `- ${(line.speaker || line.speaker_name || 'Speaker')}: ${(line.text || line.content || '')}\n`;
  });
}
if (staticData._run) {
  staticData._run.matched += 1;
  if (updatedAt > staticData._run.checkpointAfterCandidate) staticData._run.checkpointAfterCandidate = updatedAt;
}
return [{ json: { skipWrite: false, noteId, updatedAt, fileName, filePath, markdown } }];

const staticData = $getWorkflowStaticData('global');
if (staticData._run) staticData._run.written += 1;
return items;

const staticData = $getWorkflowStaticData('global');
const run = staticData._run || {};
const checkpointBefore = run.checkpointBefore || null;
const checkpointAfter = run.failed > 0 ? checkpointBefore : (run.checkpointAfterCandidate || checkpointBefore);
if (run.failed > 0) {
  throw new Error(`Granola export failed for ${run.failed} note(s). Checkpoint remains ${checkpointBefore}`);
}
staticData.granolaCheckpointUpdatedAt = checkpointAfter;
return [{ json: {
  notes_scanned: run.scanned || 0,
  notes_matched: run.matched || 0,
  notes_written: run.written || 0,
  notes_skipped: run.skipped || 0,
  notes_failed: run.failed || 0,
  checkpoint_before: checkpointBefore,
  checkpoint_after: checkpointAfter,
  pages_fetched: run.pages || 0
} }];
